using Application.ResultPattern;

namespace Api.Extentions;

/// <summary>
/// Maps <see cref="Result"/> failures to RFC 7807 problem responses with correct status codes.
/// </summary>
public static class CalendarProblemResults
{
    /// <summary>
    /// Returns 200 OK on success or a problem response mapped from <see cref="ErrorType"/>.
    /// </summary>
    public static IResult FromResult(Result result)
    {
        if (result.IsSuccess)
            return Results.Ok(true);

        return FromError(result.Error!);
    }

    /// <summary>
    /// Returns 200 OK with value on success or a problem response on failure.
    /// </summary>
    public static IResult FromResult<T>(Result<T> result)
    {
        if (result.IsSuccess)
            return Results.Ok(result.Value);

        return FromError(result.Error!);
    }

    private static IResult FromError(Error error)
    {
        var status = error.ErrorType switch
        {
            ErrorType.NotFound => StatusCodes.Status404NotFound,
            ErrorType.AccessForbidden => StatusCodes.Status403Forbidden,
            ErrorType.Conflict => StatusCodes.Status409Conflict,
            _ => StatusCodes.Status400BadRequest
        };

        return Results.Problem(error.Description, statusCode: status);
    }
}

